from EfiPy2.MdePkg.IndustryStandard.Acpi import EFI_ACPI_2_0_SYSTEM_MEMORY, EFI_ACPI_2_0_SYSTEM_IO, EFI_ACPI_2_0_PCI_CONFIGURATION_SPACE
AcpiAddressSpaceIdDict = {
  EFI_ACPI_2_0_SYSTEM_MEMORY              : 'EFI_ACPI_2_0_SYSTEM_MEMORY',
  EFI_ACPI_2_0_SYSTEM_IO                  : 'EFI_ACPI_2_0_SYSTEM_IO',
  EFI_ACPI_2_0_PCI_CONFIGURATION_SPACE    : 'EFI_ACPI_2_0_PCI_CONFIGURATION_SPACE'

}

from EfiPy2.MdePkg.Uefi.UefiMultiPhase import EfiResetCold, EfiResetWarm, EfiResetShutdown, EfiResetPlatformSpecific

UefiResetTypeDict = {
    EfiResetCold                : 'EfiResetCold',
    EfiResetWarm                : 'EfiResetWarm',
    EfiResetShutdown            : 'EfiResetShutdown',
    EfiResetPlatformSpecific    : 'EfiResetPlatformSpecific'
}

class Reset:

    @staticmethod
    def Cf9Reset (Value: int, DryRun: bool):
        print (f'Process IO port CF9 reset with value 0x{Value:02X}')

        if DryRun: return;

        from EfiPy2.Lib.X86Processor import Me
        print ('Command sending')
        Me.Iow8 (0xCF9, Value)

    @staticmethod
    def AcpiReset (DryRun: bool):

        from EfiPy2.Lib.Acpi.AcpiRetrieve   import ExtractTable
        from EfiPy2.Lib.Acpi.AcpiFacpParser import AcpiFacpParser

        FacpRaw = ExtractTable (b'FACP', 0)
        FacpObj, FacpType = AcpiFacpParser (FacpRaw)

        print (f'ACPI reset, ID: {AcpiAddressSpaceIdDict[FacpObj.ResetReg.AddressSpaceId]}, Address: 0x{FacpObj.ResetReg.Address:X}, Value: 0x{FacpObj.ResetValue:X}')

        from EfiPy2.Lib.X86Processor import Me

        if FacpObj.ResetReg.AddressSpaceId == EFI_ACPI_2_0_SYSTEM_MEMORY:

            if DryRun: return;

            print ('Command sending')
            Me.MemSet32 (FacpObj.ResetReg.Address, FacpObj.ResetValue)
            return

        elif FacpObj.ResetReg.AddressSpaceId == EFI_ACPI_2_0_SYSTEM_IO:

            if DryRun: return;

            print ('Command sending')
            Me.Iow8 (FacpObj.ResetReg.Address, FacpObj.ResetValue)
            return

        elif FacpObj.ResetReg.AddressSpaceId == EFI_ACPI_2_0_PCI_CONFIGURATION_SPACE:

            Bus = 0
            Dev, Func, Reg = (FacpObj.ResetReg.Address >> 32) & 0xFFFF, (FacpObj.ResetReg.Address >> 16) & 0xFFFF, FacpObj.ResetReg.Address & 0xFFFF
            import EfiPy2.MdePkg.IndustryStandard.Pci as pci

            PciCfgOffset  = pci.PCI_ECAM_ADDRESS (Bus, Dev, Func, Reg)

            from EfiPy2 import UINT32
            from EfiPy2.Lib.EfiPyPci import GetPciEcam
            PciResetAddress = GetPciEcam (Bus, Dev, Func, Reg) + PciCfgOffset

            print (f'Reset.... {Bus}:{Dev}.{Func} Reg: 0x{Reg:02X}, Offset: 0x{PciCfgOffset:X}')

            if DryRun: return;

            print ('Command sending')
            PciResetPointer = UINT32.from_address (PciResetAddress)
            PciResetPointer[0] = FacpObj.ResetValue

            return

    @staticmethod
    def KeyboardReset (DryRun: bool):
        print (f'keyboard reset, This function should work in X86 real mode, only.')
        print (f'Process IO port 0x64 reset with value 0xFE')

        if DryRun: return;

        from EfiPy2.Lib.X86Processor import Me
        print ('Command sending')
        Me.Iow8 (0x64, 0xFE)

    @staticmethod
    def PortReset (offset, value, DryRun: bool):
        print (f'Port reset')
        print (f'Process IO port 0x{offset:04X} reset with value 0x{value:02X}')

        if DryRun: return;

        from EfiPy2.Lib.X86Processor import Me
        print ('Command sending')
        Me.Iow8 (offset, value)

    @staticmethod
    def CmosReset (DryRun: bool):
        print (f'CMOS reset, This needs to be confirm.')
        print (f'Process COMS offert 0x0F reset with value 0x00')

        if DryRun: return;

        from EfiPy2.Lib.X86Processor import Me
        print ('Command sending')
        Me.IndexDataw32 (0x70, 0x71, 0x0F, 0x00)

    @staticmethod
    def UefiOp (ResetType, DryRun: bool):
        print (f'UEFI Runtime Service SystemReset({UefiResetTypeDict [ResetType]}).')

        if DryRun: return;

        from EfiPy2 import gRT, EFI_SUCCESS
        print ('Command sending')
        gRT.ResetSystem (ResetType, EFI_SUCCESS, 0, None)
